            for c in range(col + 1, ws.max_column + 1):
                val = ws.cell(row=row, column=c).value
                if val is not None:
                    month_range.append(str(val))
                else:
                    break

# If we didn't find headers, let's look for named ranges or assume common positions
if not codes2_range or not month_range:
    # Let's try to find the data by looking for numeric codes (01-12) and month abbreviations
    for row in range(1, min(20, ws.max_row + 1)):  # Check first 20 rows
        row_values = []
        for col in range(1, ws.max_column + 1):
            val = ws.cell(row=row, column=col).value
            if val is not None:
                row_values.append(str(val))

        # Check if this row contains month codes (01, 02, etc.)
        if any(re.match(r'^\d{2}$', val) for val in row_values):
            codes2_range = [val for val in row_values if re.match(r'^\d{2}$', val)]

        # Check if this row contains month abbreviations
        month_abbrevs = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 
                        'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC']
        if any(val.upper() in month_abbrevs for val in row_values if isinstance(val, str)):
            month_range = [val for val in row_values if val.upper() in month_abbrevs]

# Create mapping dictionary
code_to_month = {}
if len(codes2_range) == len(month_range):
    code_to_month = dict(zip(codes2_range, month_range))
