# Function to subtract 30 minutes from a time, handling midnight crossover
def calculate_cutoff_time(std_time):
    if std_time is None:
        return None

    # If it's already a datetime.time object
    if isinstance(std_time, datetime.time):
        # Convert to datetime for calculation
        base_date = datetime.date(2000, 1, 1)  # Arbitrary date
        dt = datetime.datetime.combine(base_date, std_time)

        # Subtract 30 minutes
        cutoff_dt = dt - datetime.timedelta(minutes=30)

        # Return just the time portion
        return cutoff_dt.time()

    # If it's a datetime object
    elif isinstance(std_time, datetime.datetime):
        cutoff_dt = std_time - datetime.timedelta(minutes=30)
        return cutoff_dt.time()

    # If it's a string, try to parse it
    elif isinstance(std_time, str):
        try:
            # Try to parse as time
            parsed_time = datetime.datetime.strptime(std_time, '%H:%M:%S').time()
            base_date = datetime.date(2000, 1, 1)
            dt = datetime.datetime.combine(base_date, parsed_time)
            cutoff_dt = dt - datetime.timedelta(minutes=30)
            return cutoff_dt.time()
        except:
            try:
                # Try to parse as time without seconds
                parsed_time = datetime.datetime.strptime(std_time, '%H:%M').time()
                base_date = datetime.date(2000, 1, 1)
                dt = datetime.datetime.combine(base_date, parsed_time)
                cutoff_dt = dt - datetime.timedelta(minutes=30)
                return cutoff_dt.time()
            except:
                return None

    return None

